+    private static void rewriteImports(Launcher launcher) {
+        launcher.getModel().getAllTypes().forEach(type -> {
+            List<CtPackageReference> toRemove = new ArrayList<>();
+            for (CtPackageReference ref : type.getPackage().getFactory().Package().getUsedPackages()) {
+                String qn = ref.getQualifiedName();
+                if (qn.startsWith("org.spongepowered.api.command.args")
+                        || qn.startsWith("org.spongepowered.api.command.spec")
+                        || qn.startsWith("org.spongepowered.api.command")
+                        || qn.startsWith("org.spongepowered.api.event.game.state")
