+            }
+            method.getParameters().forEach(parameter -> {
+                String qn = parameter.getType().getQualifiedName();
+                if (OLD_COMMAND_SOURCE.equals(qn)) {
+                    parameter.setType(method.getFactory().createCtTypeReference(NEW_COMMAND_SOURCE));
+                } else if (OLD_COMMAND_CONTEXT.equals(qn)) {
+                    parameter.setType(method.getFactory().createCtTypeReference(NEW_COMMAND_CONTEXT));
+                }
+            });
+        });
+
+        type.getConstructors().forEach(ctor -> ctor.getParameters().forEach(parameter -> {
+            if (OLD_COMMAND_SOURCE.equals(parameter.getType().getQualifiedName())) {
+                parameter.setType(ctor.getFactory().createCtTypeReference(NEW_COMMAND_SOURCE));
+            }
+        }));
+    }
